#include <library.h>#include <iostream>#include <iomanip>bool leap_year(int year){if (year % 400 == 0)return true;if (year % 100 == 0)return false;if (year % 4 == 0)return true;return false;}int day_of_year(int year, int month, int day){int days_in_year_before_month[] = {0, 31, 59, 90, 120, 151, 181, 212, 243, 273, 304, 334};    int day_of_year = days_in_year_before_month[month - 1] + day;    if (leap_year(year) && month > 2)    {        day_of_year += 1;    }    return day_of_year;}int days_since_year_zero(int year, int month, int day){int total_days = 0;    for (int y = 0; y < year; ++y)    {        total_days += (leap_year(y) ? 366 : 365);    }    total_days += day_of_year(year, month, day);    return total_days;}int day_of_week(int year, int month, int day){int total_days = days_since_year_zero(year, month, day);    return (total_days + 5) % 7;}int days_in_month(int year, int month){int days[] = {31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31};if (month == 2 && leap_year(year)) {return 29;}return days[month - 1];}void print_day_labels(const char* days_of_week[], int index = 0){if (index == 7) return;std::cout << std::setw(3) << days_of_week[index];print_day_labels(days_of_week, index + 1);}void print_initial_spacing(int spaces){if (spaces == 0) return;std::cout << "   ";print_initial_spacing(spaces - 1);}void print_day_numbers(int current_day, int first_day, int num_days){if (current_day > num_days) return;    std::cout << std::setw(3) << current_day;    if ((first_day + current_day) % 7 == 0) {        std::cout << std::endl;    }    print_day_numbers(current_day + 1, first_day, num_days);}void print_calendar(int year, int month){const char* days_of_week[] = {"Su", "Mo", "Tu", "We", "Th", "Fr", "Sa"};    int first_day = day_of_week(year, month, 1);    int num_days = days_in_month(year, month);    print_day_labels(days_of_week);    std::cout << std::endl;    print_initial_spacing(firs